import { getFreelancerDashboard } from "../../api/api";
import { useNavigate } from "react-router-dom";

const fmt = (d) =>
  d ? new Date(d).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" }) : "";

const statusConfig = {
  accepted: { bg: "#d1fae5", color: "#065f46", dot: "#10b981" },
  rejected: { bg: "#fee2e2", color: "#991b1b", dot: "#ef4444" },
  pending:  { bg: "#fef3c7", color: "#92400e", dot: "#f59e0b" },
};

export default function FreelancerDashboard() {
  const user = JSON.parse(localStorage.getItem("user") || "{}");
  const navigate = useNavigate();
  const [data, setData] = useState({ activeProjects: 0, pendingProposals: 0, projects: [] });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getFreelancerDashboard()
      .then((r) => { setData(r.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  if (loading) return (
    <div style={styles.loadWrap}>
      <div style={styles.spinner} />
    </div>
  );

  const accepted = data.projects?.filter((p) => p.proposal_status === "accepted").length || 0;

  const statCards = [
    { label: "Applied Projects", value: data.activeProjects, icon: (
        <svg width="22" height="22" fill="none" stroke="#14b8a6" strokeWidth="1.8" viewBox="0 0 24 24"><path d="M3 7h18M3 12h18M3 17h18"/></svg>
      ), accent: "#14b8a6", lightBg: "#f0fdfa", sub: "Total applied" },
    { label: "Total Proposals", value: data.pendingProposals, icon: (
        <svg width="22" height="22" fill="none" stroke="#8b5cf6" strokeWidth="1.8" viewBox="0 0 24 24"><path d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414A1 1 0 0119 9.414V19a2 2 0 01-2 2z"/></svg>
      ), accent: "#8b5cf6", lightBg: "#f5f3ff", sub: "Submitted" },
    { label: "Accepted", value: accepted, icon: (
        <svg width="22" height="22" fill="none" stroke="#10b981" strokeWidth="1.8" viewBox="0 0 24 24"><path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
      ), accent: "#10b981", lightBg: "#ecfdf5", sub: "Projects won" },
    { label: "Account Type", value: "Freelancer", icon: (
        <svg width="22" height="22" fill="none" stroke="#f59e0b" strokeWidth="1.8" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/></svg>
      ), accent: "#f59e0b", lightBg: "#fffbeb", sub: user.email?.slice(0, 22) },
  ];

  return (
    <div style={styles.page}>
      {/* Header */}
      <div style={styles.header}>
        <div>
          <p style={styles.overline}>OVERVIEW</p>
          <h1 style={styles.title}>Freelancer Dashboard</h1>
          <p style={styles.subtitle}>Welcome back, <strong>{user.name}</strong> — here's your activity summary</p>
        </div>
        <button onClick={() => navigate("/freelancer/find-projects")} style={styles.primaryBtn}>
          <svg width="16" height="16" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/></svg>
          Browse Projects
        </button>
      </div>

      {/* Stat Cards */}
      <div style={styles.cardGrid}>
        {statCards.map((c, i) => (
          <div key={i} style={{ ...styles.statCard, borderTop: `3px solid ${c.accent}` }}>
            <div style={styles.statTop}>
              <div style={{ ...styles.iconBox, background: c.lightBg }}>{c.icon}</div>
              <span style={styles.statLabel}>{c.label}</span>
            </div>
            <p style={{ ...styles.statValue, color: c.accent }}>{c.value}</p>
            <p style={styles.statSub}>{c.sub}</p>
          </div>
        ))}
      </div>

      {/* Projects Table */}
      <div style={styles.tableCard}>
        <div style={styles.tableHeader}>
          <div style={styles.tableHeaderLeft}>
            <svg width="18" height="18" fill="none" stroke="#14b8a6" strokeWidth="2" viewBox="0 0 24 24"><path d="M3 7h18M3 12h18M3 17h18"/></svg>
            <h2 style={styles.tableTitle}>Projects You Applied To</h2>
          </div>
          <button onClick={() => navigate("/freelancer/find-projects")} style={styles.ghostBtn}>
            View All <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M9 18l6-6-6-6"/></svg>
          </button>
        </div>

        <table style={styles.table}>
          <thead>
            <tr style={styles.thead}>
              <th style={styles.th}>Title</th>
              <th style={styles.th}>Budget</th>
              <th style={styles.th}>Your Bid</th>
              <th style={styles.th}>Deadline</th>
              <th style={styles.th}>Status</th>
            </tr>
          </thead>
          <tbody>
            {(!data.projects || data.projects.length === 0) ? (
              <tr><td colSpan={5} style={styles.emptyRow}>
                <div style={styles.emptyState}>
                  <svg width="40" height="40" fill="none" stroke="#cbd5e1" strokeWidth="1.5" viewBox="0 0 24 24"><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/></svg>
                  <p>No projects yet. Start browsing!</p>
                </div>
              </td></tr>
            ) : data.projects.map((p) => {
              const s = statusConfig[p.proposal_status] || statusConfig.pending;
              return (
                <tr key={p.id} style={styles.trow}>
                  <td style={styles.td}>
                    <p style={styles.tdTitle}>{p.title}</p>
                    <p style={styles.tdSub}>{p.description?.slice(0, 55)}...</p>
                  </td>
                  <td style={{ ...styles.td, fontWeight: 600, color: "#0f172a" }}>₹{p.budget}</td>
                  <td style={{ ...styles.td, fontWeight: 600, color: "#14b8a6" }}>{p.my_bid ? `₹${p.my_bid}` : "—"}</td>
                  <td style={{ ...styles.td, color: "#64748b" }}>{p.deadline ? fmt(p.deadline) : "—"}</td>
                  <td style={styles.td}>
                    <span style={{ ...styles.badge, background: s.bg, color: s.color }}>
                      <span style={{ ...styles.dot, background: s.dot }} />
                      {p.proposal_status || "pending"}
                    </span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

const styles = {
  page: { background: "#f8fafc", minHeight: "100vh", padding: "36px 40px", fontFamily: "'Inter', 'Segoe UI', sans-serif" },
  loadWrap: { background: "#f8fafc", minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center" },
  spinner: { width: 36, height: 36, borderRadius: "50%", border: "3px solid #e2e8f0", borderTopColor: "#14b8a6", animation: "spin 0.8s linear infinite" },
  header: { display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 32 },
  overline: { fontSize: 11, fontWeight: 700, color: "#94a3b8", letterSpacing: "1.5px", textTransform: "uppercase", margin: "0 0 6px" },
  title: { fontSize: 26, fontWeight: 700, color: "#0f172a", margin: "0 0 4px", letterSpacing: "-0.5px" },
  subtitle: { fontSize: 14, color: "#64748b", margin: 0 },
  primaryBtn: { display: "flex", alignItems: "center", gap: 8, padding: "10px 20px", borderRadius: 8, border: "none", background: "#0f766e", color: "white", fontSize: 13, fontWeight: 600, cursor: "pointer", letterSpacing: "0.1px" },
  cardGrid: { display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 16, marginBottom: 28 },
  statCard: { background: "white", borderRadius: 12, padding: "20px 22px", boxShadow: "0 1px 3px rgba(0,0,0,0.06)", border: "1px solid #e2e8f0" },
  statTop: { display: "flex", alignItems: "center", gap: 10, marginBottom: 14 },
  iconBox: { width: 40, height: 40, borderRadius: 10, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 },
  statLabel: { fontSize: 12, fontWeight: 600, color: "#64748b", textTransform: "uppercase", letterSpacing: "0.6px" },
  statValue: { fontSize: 30, fontWeight: 800, margin: "0 0 2px", letterSpacing: "-1px" },
  statSub: { fontSize: 11, color: "#94a3b8", margin: 0 },
  tableCard: { background: "white", border: "1px solid #e2e8f0", borderRadius: 14, overflow: "hidden", boxShadow: "0 1px 3px rgba(0,0,0,0.06)" },
  tableHeader: { display: "flex", justifyContent: "space-between", alignItems: "center", padding: "18px 24px", borderBottom: "1px solid #f1f5f9" },
  tableHeaderLeft: { display: "flex", alignItems: "center", gap: 10 },
  tableTitle: { fontSize: 15, fontWeight: 700, color: "#0f172a", margin: 0 },
  ghostBtn: { display: "flex", alignItems: "center", gap: 4, fontSize: 12, fontWeight: 600, color: "#14b8a6", background: "#f0fdfa", border: "1px solid #99f6e4", borderRadius: 7, padding: "6px 14px", cursor: "pointer" },
  table: { width: "100%", borderCollapse: "collapse" },
  thead: { background: "#f8fafc" },
  th: { padding: "11px 24px", fontSize: 11, fontWeight: 700, color: "#94a3b8", textAlign: "left", textTransform: "uppercase", letterSpacing: "0.8px", borderBottom: "1px solid #f1f5f9" },
  trow: { borderBottom: "1px solid #f8fafc", transition: "background 0.15s" },
  td: { padding: "14px 24px", fontSize: 13, color: "#374151", verticalAlign: "middle" },
  tdTitle: { fontSize: 13, fontWeight: 600, color: "#0f172a", margin: "0 0 2px" },
  tdSub: { fontSize: 11, color: "#94a3b8", margin: 0 },
  badge: { display: "inline-flex", alignItems: "center", gap: 5, padding: "4px 10px", borderRadius: 20, fontSize: 11, fontWeight: 700, textTransform: "capitalize" },
  dot: { width: 6, height: 6, borderRadius: "50%", flexShrink: 0 },
  emptyRow: { padding: "48px 24px", textAlign: "center" },
  emptyState: { display: "flex", flexDirection: "column", alignItems: "center", gap: 10, color: "#94a3b8", fontSize: 13 },
};
